import { ImageResponse } from "next/og";

export const size = { width: 1200, height: 630 };
export const contentType = "image/png";
export const alt = "Watchruum: Never get spoiled again";

// Social share preview (the Watchruum promo art, letterboxed onto the brand
// background at 1200x630). Embedded as a data URL so it renders with no network
// fetch or public-asset lookup, and is served publicly (see src/proxy.ts).
const OG_IMAGE = "data:image/jpeg;base64,";

export default function OpengraphImage() {
  return new ImageResponse(
    (
      // eslint-disable-next-line @next/next/no-img-element
      <img src={OG_IMAGE} width={1200} height={630} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
    ),
    { ...size },
  );
}
